function Foo({ mode }: Props) {
  let bodyContent: React.ReactNode;
  let header: JSX.Element = <div />;
  let footer: ReactNode | null = null;

  if (mode === 'a') {
    bodyContent = <A />;
  } else {
    bodyContent = <B />;
  }
  return <div>{header}{bodyContent}{footer}</div>;
}
